preConditions.sqlCheck:
SELECT COUNT(*)
FROM sys.databases
WHERE name = 'liquibase_lab';

changeSet.sql:
IF NOT EXISTS (SELECT name FROM sys.databases WHERE name = 'liquibase_lab')
BEGIN
    CREATE DATABASE liquibase_lab COLLATE Latin1_General_100_CI_AS_SC_UTF8;
    RAISERROR ('Database "liquibase_lab" has been created.', 10, 1) WITH NOWAIT;
END
ELSE
BEGIN
    RAISERROR ('Database "liquibase_lab" already exists.', 10, 1) WITH NOWAIT;
END

preConditions.sqlCheck:
SELECT COUNT(*)
FROM sys.sql_logins
WHERE name = 'lab_user';

changeSet.sql:
USE liquibase_lab;
IF NOT EXISTS (SELECT 1 FROM sys.database_principals WHERE name = 'lab_user') BEGIN CREATE USER lab_user FOR LOGIN lab_user; END
-- Assign roles for full lab access IF NOT EXISTS ( SELECT 1 FROM sys.database_role_members drm JOIN sys.database_principals r ON drm.role_principal_id = r.principal_id JOIN sys.database_principals u ON drm.member_principal_id = u.principal_id WHERE r.name = 'db_datareader' AND u.name = 'lab_user' ) BEGIN EXEC sp_addrolemember 'db_datareader', 'lab_user'; END
IF NOT EXISTS ( SELECT 1 FROM sys.database_role_members drm JOIN sys.database_principals r ON drm.role_principal_id = r.principal_id JOIN sys.database_principals u ON drm.member_principal_id = u.principal_id WHERE r.name = 'db_datawriter' AND u.name = 'lab_user' ) BEGIN EXEC sp_addrolemember 'db_datawriter', 'lab_user'; END
IF NOT EXISTS ( SELECT 1 FROM sys.database_role_members drm JOIN sys.database_principals r ON drm.role_principal_id = r.principal_id JOIN sys.database_principals u ON drm.member_principal_id = u.principal_id WHERE r.name = 'db_ddladmin' AND u.name = 'lab_user' ) BEGIN EXEC sp_addrolemember 'db_ddladmin', 'lab_user'; END
USE master;
